#include<bits/stdc++.h>
using namespace std;

const int N = 100005;
const int L = 17;

vector<int> g[N];
int f[N][L], d[N];
int n, q;

void dfs(int u, int fa, int dep) {
    f[u][0] = fa;
    d[u] = dep;
    for (int i = 1; i < L; i++) {
        f[u][i] = f[f[u][i-1]][i-1];
    }
    for (int v : g[u]) {
        if (v != fa) dfs(v, u, dep + 1);
    }
}

int lca(int x, int y) {
    if (d[x] < d[y]) swap(x, y);
    int diff = d[x] - d[y];
    for (int i = 0; i < L; i++) {
        if (diff >> i & 1) x = f[x][i];
    }
    if (x == y) return x;
    for (int i = L-1; i >= 0; i--) {
        if (f[x][i] != f[y][i]) {
            x = f[x][i];
            y = f[y][i];
        }
    }
    return f[x][0];
}

int dist(int x, int y) {
    int l = lca(x, y);
    return d[x] + d[y] - 2 * d[l];
}

bool on_path(int x, int u, int v) {
    return dist(u, x) + dist(x, v) == dist(u, v);
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0);

    cin >> n >> q;
    for (int i = 1; i < n; i++) {
        int u, v;
        cin >> u >> v;
        g[u].push_back(v);
        g[v].push_back(u);
    }

    dfs(1, 1, 0);

    while (q--) {
        int a, b, c, d;
        cin >> a >> b >> c >> d;

        int lab = lca(a, b);
        int lcd = lca(c, d);

        if (on_path(lab, c, d) || on_path(lcd, a, b)) {
            cout << "Y\n";
        } else {
            cout << "N\n";
        }
    }

    return 0;
}
